code = """import json
import pandas as pd

# Correctly access the results from the previous tool call, it's already a list of dictionaries
order_item_ids_data = locals()['var_function-call-16210960612240012878']['query_db_response']['results']
order_item_ids = [item['Id'] for item in order_item_ids_data]

# Clean the IDs by removing leading '#' and trailing spaces
cleaned_order_item_ids = [item.replace('#', '').strip() for item in order_item_ids]

# Construct the WHERE clause for the SQL query
# Ensure that the tuple for IN clause is correctly formatted, even for a single item
if len(cleaned_order_item_ids) == 1:
    ids_tuple = f"('{cleaned_order_item_ids[0]}')"
elif len(cleaned_order_item_ids) > 1:
    ids_list_str = [f"'{item}'" for item in cleaned_order_item_ids]
    ids_tuple = f"({', '.join(ids_list_str)})"
else:
    ids_tuple = "('')" # If no IDs found, create an empty tuple to prevent SQL error

# Format the SQL query to fetch cases within the last 5 months for the cleaned order item IDs
# Assuming today's date is 2023-01-16, five months ago would be 2022-08-16
# PostgreSQL date format is 'YYYY-MM-DD'

sql_query_cases = f'''
SELECT issueid__c
FROM "Case"
WHERE orderitemid__c IN {ids_tuple}
  AND createddate >= '2022-08-16'
''';

print('__RESULT__:')
print(json.dumps(sql_query_cases))"""

